import 'package:injectable/injectable.dart'; import '../services/keep_alive_service.dart'; import '../utils/app_logger.dart'; @singleton class ForegroundServiceManager { final KeepAliveService _svc; ForegroundServiceManager(this._svc); Future<void> start() async { await _svc.startForegroundService(); AppLogger.info('Foreground service started'); } Future<void> stop() async { await _svc.stopForegroundService(); AppLogger.info('Foreground service stopped'); } Future<void> update(String title, String text) => _svc.updateNotification(title, text); }